def trimmed_mean(nums):
    if not nums:
        return None

    nums.sort()
    length = len(nums)
    if length < 3:
        return sum(nums) / length

    min_index, max_index = 1, length - 2
    trimmed_sum = sum(nums[min_index:max_index])
    return trimmed_sum / (length - 2)
